                int b=(nmask>>j)&1;

                setBit(nmask,i,b);

                setBit(nmask,j,a);

                if(d[j][nmask]>d[s.pos][s.mask]+cost){

                    d[j][nmask]=d[s.pos][s.mask]+cost;

                    que.push(Sit(d[j][nmask],j,nmask));

                }

            }

        }

    }

    int res=INF;

    for(int i=0;i<n;i++)res=min(res,d[i][t]);

    return res;

}

