#include <iostream>

#include <cstring>

#define inf 0x3f3f3f3f



using namespace std;



int m,n,temp1,temp2,ans,used[10005],mincost[10005],mindis[10005],mark;



struct road

{

    int from,to,l,w;

}r[20005];



void Dijkstra()

{

    memset(used,0,sizeof(used));

    memset(mincost,inf,sizeof(mincost));

    memset(mindis,inf,sizeof(mindis));

    for(int i=1;i<=n;i++)

    {

        if(r[i].from==1)

        {

            mincost[r[i].to]=r[i].w;

            mindis[r[i].to]=r[i].l;

        }

        if(r[i].to==1)

        {

            mincost[r[i].from]=r[i].w;

            mindis[r[i].from]=r[i].l;

        }

    }

    used[1]=1;

    for(int i=2;i<=m;i++)

    {

        mark=-1;

        for(int i=1;i<=m;i++)

            if(!used[i]&&(mark==-1||mindis[i]<mindis[mark]))

                mark=i;

        used[mark]=1;

        ans+=mincost[mark];

        for(int i=1;i<=n;i++)

        {

            if(r[i].from==mark)

            {

                if(!used[r[i].to])

                {

                    if(mindis[r[i].to]>mindis[r[i].from]+r[i].l)

                    {

                        mindis[r[i].to]=mindis[r[i].from]+r[i].l;

                        mincost[r[i].to]=r[i].w;

                    }

                    if(mindis[r[i].to]==mindis[r[i].from]+r[i].l)

                        mincost[r[i].to]=min(mincost[r[i].to],r[i].w);

                }

            }

            if(r[i].to==mark)

            {

                if(!used[r[i].from])

                {

                    if(mindis[r[i].from]>mindis[r[i].to]+r[i].l)

                    {

                        mindis[r[i].from]=mindis[r[i].to]+r[i].l;

                        mincost[r[i].from]=r[i].w;

                    }

                    if(mindis[r[i].from]==mindis[r[i].to]+r[i].l)

                        mincost[r[i].from]=min(mincost[r[i].from],r[i].w);

                }

            }

        }

    }

}



int main()

{

    ios::sync_with_stdio(false);

    while(cin>>m>>n&&m)

    {

        ans=0;

        for(int i=1;i<=n;i++)

            cin>>r[i].from>>r[i].to>>r[i].l>>r[i].w;

        Dijkstra();

        cout<<ans<<endl;

    }

    return 0;

}

